={{ (() => {
  const original = $('Llega un formulario').item.json || {};
  const form = original.body || $json.body || $json || {};
  return {
    providerEventId: form.timestamp || ((form.email || '') + ':' + (form.phone || '')),
    name: form.name,
    email: form.email,
    phone: form.phone,
    interesting: form.interesting,
    message: form.message,
    timestamp: form.timestamp,
    source: form.source || 'website_coradir_homes_form',
    profileType: form.profileType,
    transactionType: form.transactionType,
    sourceDetail: form.source || 'website_coradir_homes_form',
    webhookUrl: original.webhookUrl,
    rawPayload: original
  };
})() }}

={{ (() => {
